import React, { useState } from 'react';
import { useLocation, useParams, useNavigate } from 'react-router-dom';

const StudySession = ({ markDayComplete }) => {
  const { day } = useParams();
  const { state } = useLocation();
  const navigate = useNavigate();
  const [userAnswer, setUserAnswer] = useState('');
  const [isFinished, setIsFinished] = useState(false);

  const handleComplete = () => {
    if (userAnswer.length < 5) return alert("Explain what you learned!");
    
    // This updates the state in App.js
    markDayComplete(day); 
    
    navigate('/dashboard');
  };

  return (
    <div style={{ padding: '40px', textAlign: 'center' }}>
      <h2>Studying: {state?.topic}</h2>
      <p>Key Points: [AI Generated Points Here]</p>
      
      {!isFinished ? (
        <button onClick={() => setIsFinished(true)} style={{ padding: '20px', background: '#9b59b6', color: 'white' }}>
          Finish Session (2s Test)
        </button>
      ) : (
        <div style={{ marginTop: '20px' }}>
          <h4>AI Challenge: How does {state?.topic} work?</h4>
          <textarea onChange={(e) => setUserAnswer(e.target.value)} style={{ width: '100%', height: '100px' }} />
          <button onClick={handleComplete} style={{ marginTop: '10px', padding: '10px 20px', background: '#2ecc71', color: 'white' }}>
            Verify & Save Progress
          </button>
        </div>
      )}
    </div>
  );
};

export default StudySession;
